   126→func callResource(ctx context.Context, req *backend.CallResourceRequest, sender backend.CallResourceResponseSender, dsInfo *datasourceInfo, plog log.Logger, tracer trace.Tracer) error {
   127→	url := req.URL
   128→
   129→	lokiURL := fmt.Sprintf("/loki/api/v1/%s", url)
   130→
   131→	ctx, span := tracer.Start(ctx, "datasource.loki.CallResource", trace.WithAttributes(
   132→		attribute.String("url", lokiURL),
   133→	))
   134→	defer span.End()
   135→
   136→	api := newLokiAPI(dsInfo.HTTPClient, dsInfo.URL, plog, tracer)
   137→
   138→	var rawLokiResponse RawLokiResponse
   139→	var err error
   140→
   141→	// suggestions is a resource endpoint that will return label and label value suggestions based
   142→	// on queries and the existing scope. By moving this to the backend we can use the logql parser to
   143→	// rewrite queries safely.
   144→	if req.Method == http.MethodPost && strings.EqualFold(req.Path, "suggestions") {
   145→		rawLokiResponse, err = GetSuggestions(ctx, api, req)
   146→		if err != nil {
   147→			span.RecordError(err)
   148→			span.SetStatus(codes.Error, err.Error())
   149→			plog.FromContext(ctx).Error("Failed to get suggestions from loki", "err", err)
   150→			return err
   151→		}
   152→	} else {
   153→		rawLokiResponse, err = api.RawQuery(ctx, lokiURL)
   154→		if err != nil {
   155→			span.RecordError(err)
   156→			span.SetStatus(codes.Error, err.Error())
   157→			plog.Error("Failed resource call from loki", "err", err, "url", lokiURL)
   158→			return err
   159→		}
   160→	}
   161→
   162→	respHeaders := map[string][]string{
   163→		"content-type": {"application/json"},
   164→	}
   165→
   166→	// frontend sets the X-Grafana-Cache with the desired response cache control value
   167→	if len(req.GetHTTPHeaders().Get("X-Grafana-Cache")) > 0 {
   168→		respHeaders["X-Grafana-Cache"] = []string{"y"}
   169→		respHeaders["Cache-Control"] = []string{req.GetHTTPHeaders().Get("X-Grafana-Cache")}
   170→	}
   171→
   172→	if rawLokiResponse.Encoding != "" {
   173→		respHeaders["content-encoding"] = []string{rawLokiResponse.Encoding}
   174→	}
   175→	return sender.Send(&backend.CallResourceResponse{
   176→		Status:  rawLokiResponse.Status,
   177→		Headers: respHeaders,
   178→		Body:    rawLokiResponse.Body,
   179→	})
   180→}
