   116→func (s *Service) CallResource(ctx context.Context, req *backend.CallResourceRequest, sender backend.CallResourceResponseSender) error {
   117→	dsInfo, err := s.getDSInfo(ctx, req.PluginContext)
   118→	logger := s.logger.FromContext(ctx)
