   198→func queryData(ctx context.Context, req *backend.QueryDataRequest, dsInfo *datasourceInfo, responseOpts ResponseOpts, tracer trace.Tracer, plog log.Logger, runInParallel bool, logQLScopes bool) (*backend.QueryDataResponse, error) {
   199→	result := backend.NewQueryDataResponse()
   200→
   201→	api := newLokiAPI(dsInfo.HTTPClient, dsInfo.URL, plog, tracer)
   202→
   203→	start := time.Now()
   204→	queries, err := parseQuery(req, logQLScopes)
   205→	if err != nil {
   206→		plog.Debug("Failed to prepare request to Loki", "error", err, "duration", time.Since(start), "queriesLength", len(queries), "stage", stagePrepareRequest)
   207→		return result, err
   208→	}
   209→
   210→	plog.Debug("Prepared request to Loki", "duration", time.Since(start), "queriesLength", len(queries), "stage", stagePrepareRequest, "runInParallel", runInParallel)
   211→
   212→	ctx, span := tracer.Start(ctx, "datasource.loki.queryData.runQueries", trace.WithAttributes(
   213→		attribute.Bool("runInParallel", runInParallel),
   214→		attribute.Int("queriesLength", len(queries)),
   215→	))
   216→	if req.GetHTTPHeader("X-Query-Group-Id") != "" {
   217→		span.SetAttributes(attribute.String("query_group_id", req.GetHTTPHeader("X-Query-Group-Id")))
   218→	}
   219→	defer span.End()
   220→	start = time.Now()
   221→
   222→	// We are testing running of queries in parallel behind feature flag
   223→	if runInParallel {
   224→		resultLock := sync.Mutex{}
   225→		err = concurrency.ForEachJob(ctx, len(queries), 10, func(ctx context.Context, idx int) error {
   226→			query := queries[idx]
   227→			queryRes := executeQuery(ctx, query, req, runInParallel, api, responseOpts, tracer, plog)
   228→
   229→			resultLock.Lock()
   230→			defer resultLock.Unlock()
   231→			result.Responses[query.RefID] = queryRes
   232→			return nil // errors are saved per-query,always return nil
   233→		})
   234→	} else {
   235→		for _, query := range queries {
   236→			queryRes := executeQuery(ctx, query, req, runInParallel, api, responseOpts, tracer, plog)
   237→			result.Responses[query.RefID] = queryRes
   238→		}
   239→	}
   240→	plog.Debug("Executed queries", "duration", time.Since(start), "queriesLength", len(queries), "runInParallel", runInParallel)
   241→	return result, err
   242→}
   243→
   244→func executeQuery(ctx context.Context, query *lokiQuery, req *backend.QueryDataRequest, runInParallel bool, api *LokiAPI, responseOpts ResponseOpts, tracer trace.Tracer, plog log.Logger) backend.DataResponse {
   245→	ctx, span := tracer.Start(ctx, "datasource.loki.queryData.runQueries.runQuery", trace.WithAttributes(
   246→		attribute.Bool("runInParallel", runInParallel),
   247→		attribute.String("expr", query.Expr),
   248→		attribute.Int64("start_unixnano", query.Start.UnixNano()),
   249→		attribute.Int64("stop_unixnano", query.End.UnixNano()),
   250→	))
   251→	if req.GetHTTPHeader("X-Query-Group-Id") != "" {
   252→		span.SetAttributes(attribute.String("query_group_id", req.GetHTTPHeader("X-Query-Group-Id")))
   253→	}
   254→
   255→	defer span.End()
   256→
   257→	queryRes, err := runQuery(ctx, api, query, responseOpts, plog)
   258→	if queryRes == nil {
   259→		// we always want to return a backend.DataResponse object, even if we received just an error
   260→		queryRes = &backend.DataResponse{}
   261→	}
   262→
   263→	if err != nil {
   264→		span.RecordError(err)
   265→		span.SetStatus(codes.Error, err.Error())
   266→		errResp := backend.ErrorResponseWithErrorSource(err)
   267→		queryRes = &errResp
   268→	}
   269→
   270→	return *queryRes
   271→}
   272→
   273→// we extracted this part of the functionality to make it easy to unit-test it
   274→func runQuery(ctx context.Context, api *LokiAPI, query *lokiQuery, responseOpts ResponseOpts, plog log.Logger) (*backend.DataResponse, error) {
   275→	res, err := api.DataQuery(ctx, *query, responseOpts)
   276→	if err != nil {
   277→		plog.Debug("Error querying loki", "error", err)
   278→		return res, err
   279→	}
   280→
   281→	for _, frame := range res.Frames {
   282→		// Skip frames without fields
   283→		if len(frame.Fields) < 2 {
   284→			continue
   285→		}
   286→
   287→		err = adjustFrame(frame, query, false, responseOpts.logsDataplane)
   288→		if err != nil {
   289→			plog.Debug("Error adjusting frame", "error", err)
   290→			return res, err
   291→		}
   292→	}
   293→
   294→	return res, nil
   295→}
   296→
   297→func (s *Service) getDSInfo(ctx context.Context, pluginCtx backend.PluginContext) (*datasourceInfo, error) {
   298→	i, err := s.im.Get(ctx, pluginCtx)
   299→	if err != nil {
   300→		return nil, backend.DownstreamError(fmt.Errorf("failed to get data source info: %w", err))
   301→	}
   302→
   303→	instance, ok := i.(*datasourceInfo)
   304→	if !ok {
   305→		return nil, backend.DownstreamError(fmt.Errorf("failed to cast data source info"))
   306→	}
   307→
   308→	return instance, nil
   309→}
   310→
   311→func isFeatureEnabled(ctx context.Context, feature string) bool {
   312→	return backend.GrafanaConfigFromContext(ctx).FeatureToggles().IsEnabled(feature)
   313→}
